var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"실종자들이라고요?","JPN":"失踪者？","ENG":"Missing people?","TWN":"失蹤人口？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"네, 저희가 일전의 전투에서 상대했던 자들의 신원은 모두 10여년 전부터 실종 후 사망처리 된 자들이었습니다.","JPN":"はい、私たちがこの前の戦闘で戦った相手は全員10年程前に失踪し、後に死亡処理された者たちでした。","ENG":"Yes. The foes we faced in our recent battles were all people who went missing for 10 years and were thought to be dead.","TWN":"是的，我們之前交手過的那些人，全都是在十幾年前失蹤，最後以死亡結案的人口。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"그 외에 일관된 점은 그들 대부분이 북방합의체 소속이라는 점이지요.","JPN":"それ以外にも一貫しているところは、彼らのほとんどが北方合意体の所属だということです。","ENG":"Another commonality we found was that they were affiliated with the Northern Union.","TWN":"除此之外，他們還有一個共通點，就是大部分都隸屬於北方和議會。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"북방합의체……","JPN":"北方合意体……","ENG":"The Northern Union...","TWN":"北方和議會……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그런 폐쇄적인 나라의 실종자들이 왜 이런 곳에 있던 걸까요?","JPN":"そんな閉鎖的な国の失踪者がどうしてこんなところにいたのでしょうか。","ENG":"Why would missing people from that closed-off country suddenly appeared here?","TWN":"那個封閉國家的失蹤人口怎麼會出現在這裡呢？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"북방합의체의 과학기관은 침식현상연구를 빌미로 인체실험을 자행하는 등 예전부터 악명이 높았습니다.","JPN":"北方合意体の科学機関は侵食現象の研究を口実に人体実験をするなど、昔から悪名が高かったのです。","ENG":"The Northern Union's science department is infamous for secretly carrying out human experiments in the name of studying the Counterside Effect.","TWN":"北方和議會的科學機構會以人體實驗私自進行侵蝕現象研究等等，因此從以前便是惡名昭彰。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"결국 관리국의 직접적인 제재 이후로 한동안 잠잠해졌지만, 얼마 후 북방합의체에 근간을 둔 다수의 태스크포스가 창설되었고요.","JPN":"管理局が直接制裁を加えてからはしばらく静かでしたが、ほどなくして北方合意体に根をもつ多数のタスクフォースが創設されました。","ENG":"Eventually, the Administration stepped in and they allegedly stopped their practices. However, a number of TASKFORCEs based on the Northern Union started to emerge.","TWN":"在管理局出手制裁後，曾經沉寂一段時間，但不久後便出現許多來自北方和議會的特遣勢力。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"신생 태스크포스 노아…… 로군요.","JPN":"新生タスクフォース・ノア……ですね。","ENG":"That's... TASKFORCE NOA...","TWN":"新興特遣勢力諾亞……嗎。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SOLDIER_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그들은 처음부터 태스크포스를 다른 목적으로 운영하고 있었던 거였어요.","JPN":"彼らは最初からタスクフォースを別目的で運営していたのですね。","ENG":"They were operating this TASKFORCE for a different purpose from the beginning.","TWN":"他們一開始經營特遣勢力的目的就是另有所圖。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SOLDIER_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"하바키의 탈출 당일 일어난 침식사태 또한 그들의 소행이라는 정황이 확인됐습니다.","JPN":"覇吐の脱出当日に起きた侵食事態もまた彼らの仕業であることも確認済みです。","ENG":"It was also confirmed that they are connected to the Corruption disaster that broke out on the day of Habaki's escape.","TWN":"目前也已經確定，幅木逃獄當天發生的侵蝕事件也是他們所為。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"그들이 이곳을 떠나지 않은 목적이 치후유님을 상대로 실험하는 것이었다면……","JPN":"彼らがここを離れなかった目的が千冬様を相手に実験することだとしたら……","ENG":"If their reasoning for staying here is to experiment on Miss Chifuyu...","TWN":"若他們沒離開這裡的目的是要對千冬進行實驗……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"하바키가 찾는 것은 나나하라 가문의 힘…… 치후유와 제가 목적이겠죠.","JPN":"覇吐が探しているのは七原家の力……千冬と私なのでしょう。","ENG":"Then Habaki's objective is to obtain the power of the Nanahara family. Which means Chifuyu and me.","TWN":"幅木要找的是七原家族的力量……那目標就是千冬和我。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"제가 바람의 목소리를 들을 수 있었다면, 이런 참변이 일어나기 전에 막았을 텐데.","JPN":"私が風の声を聞くことができていたら、このような惨事が起きる前に止められたのでしょうが。","ENG":"If I could only hear the voice of wind, all of this could have been prevented.","TWN":"要是我能夠聽到風聲，就能夠預防這種慘劇發生。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"그날 당주님의 선택으로 저희의 운명은 바뀌었고, 역신 오로치의 부활을 막을 수 있었습니다.","JPN":"あの日、ご当主様の選択で私たちの運命は変わり、疫病神オロチの復活を止めることができました。","ENG":"That day, your choice changed the fate of all of us. You were able to stop Plague God Orochi's resurgence, Lady Nanahara.","TWN":"那天堂主的選擇改變了我們的命運，還阻止了瘟神大蛇復活。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"신력을 사용한 대가가 바람의 목소리를 앗아가는 것이라 하더라도…… 저는 그 선택이 잘못되었다고 생각하지 않습니다.","JPN":"神力を使った代償が風の声を奪われることであっても……私はその選択が間違っていたとは思えません。","ENG":"Even if the price was losing the voice of wind... I do not think you made the wrong decision.","TWN":"就算使用神力的代價是會失去風聲……但我也不認為那是個錯誤的決定。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"치후유와 약속했어요. 책임을 지기 위해 치르는 희생 같은 건 더는 하지 말자고.","JPN":"千冬と約束したのです。責任を取るための犠牲などはもうやめようと。","ENG":"I made a promise with Chifuyu. That we would not make any more sacrifices out of responsibility.","TWN":"我有答應千冬，不會再因為責任而造成犧牲。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"하지만 내가 정하는 선택들은…… 결국 누군가의 희생을 치르고 마네요.","JPN":"ですが、私が決断をすると……結局誰かが犠牲となってしまうのですね。","ENG":"But the decisions I make... Someone ends up paying for it in the end.","TWN":"但我所做的決定……最終還是造成某人的犧牲。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"당주님…….","JPN":"ご当主様……","ENG":"Lady Nanahara...","TWN":"堂主……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"미안해요, 사나에. 가문연합의 당주가 나약한 소리만 해서.","JPN":"ごめんなさい、早苗。連合の当主が弱音ばかり吐いて。","ENG":"I'm sorry, Sanae. I cannot get fainthearted like this as head of the Family Alliance.","TWN":"早苗，對不起，身為家族聯盟的堂主卻老是說些喪氣話。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"전대당주께서도…… 마지막까지 그 선택을 후회하지 않으셨을 겁니다.","JPN":"先代当主も……最後までその選択を後悔なさらなかったはずです。","ENG":"Even your predecessor... She would not have regretted the decision she had made.","TWN":"我相信……前任堂主直到最後一刻都不後悔她的決定。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"네, 저도 어머니가 틀렸다고 생각하지 않아요. 덕분에 많이 의지해왔는 걸요.","JPN":"はい、私もお母様が間違ったとは思っていません。むしろそれに支えられてきたのですから。","ENG":"Yes, I do not think Mother was wrong either. That is why I have relied on her.","TWN":"是，我也不認為媽媽的決定是錯的，也因為這樣，我才能支撐到現在。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그러니 제가 그 선택을 반드시 지키겠어요.","JPN":"ですので、私がその選択を必ず守ってみせます。","ENG":"So, I will also stay with the decisions I make.","TWN":"所以我一定要守護這個決定。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"뭐어? 정면으로 나서겠다고?","JPN":"何？　正面からぶつかるじゃと？","ENG":"What? You want to face them head on?","TWN":"什麼？你說要正面迎戰？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"네, 그들이 노리고 있는 게 나나하라의 혈통이라면 반드시 저를 찾아 나타날 겁니다.","JPN":"はい、彼らの狙いが七原家の血統であるのなら必ず私を探して現れるはずです。","ENG":"Yes. If it is the Nanahara lineage, they will surely come after me.","TWN":"是的，若他們的目標是七原的血統，那他們一定會來找我。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그렇다면 마냥 경계하고 기다리기보단, 이쪽에서 먼저 움직이겠어요.","JPN":"ならばずっと警戒して待つよりは、こちらから先に動こうと思います。","ENG":"Rather than waiting for them, I choose to make the first move.","TWN":"那與其坐以待斃，不如先發制人。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"하아…… 작은 당주.","JPN":"はあ……チビ当主。","ENG":"*Sigh* Ladychild...","TWN":"哀……小堂主，"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"너, 자식을 낳은 적이라도 있는 게냐?","JPN":"お主、子どもを産んだことでもあるのか？","ENG":"Have you ever bared a child before?","TWN":"你，有生過孩子嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……네? 아, 아직은……","JPN":"……はい？　ま、まだ……","ENG":"...Huh? Oh, not yet...","TWN":"……什麼？還…還沒……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그럼 네 녀석에게 무슨 일이 생기는 순간 나나하라 가문도 대가 끊긴다는 거잖아!","JPN":"それではお主に何か起きた瞬間に七原家も絶えてしまうではないか！","ENG":"Then if something were to happen to you, your bloodline will be lost forever!","TWN":"那要是你有個什麼萬一，七原家族不就從此絕後了嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L43_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그런데도 자길 미끼로 쓰겠다고? 직계 자손이라는 개념을 이해하고 있긴 한 거냐?!","JPN":"そうと知って自分をエサにするつもりなのか？　直系子孫という概念を理解しておるのか！？","ENG":"And yet, you still wish to become bait? Do you even understand the concept of what a direct descendant is?!","TWN":"這樣你還說要拿自己當誘餌？你懂直系後裔的意思嗎？！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"하지만 제가 숨고 도망친다면, 무고한 희생자만 늘어날 뿐입니다.","JPN":"ですが私が逃げ隠れしていたら、何の罪もない犠牲者が増えるだけです。","ENG":"But if I were to run and hide, it will only lead to more unnecessary casualties.","TWN":"可是我躲起來或是逃跑，只會造成更多無辜的人犧牲。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그런 건 용납하지 않겠어요.","JPN":"それは許せません。","ENG":"And I will not tolerate that.","TWN":"我無法接受。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"……아, 나 정말! 누구 설득하는 건 지지리 재주가 없단 말이다!","JPN":"……ああ、もう！　わしに誰かを説得する才能はないんじゃ！","ENG":"...Ugh! I seriously lack any persuasion skills!","TWN":"……天啊，我的頭好痛！我看我天生就沒有說服人的口才！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"당주 동생! 너라도 네 언니를 좀 말려봐라!","JPN":"当主の妹！　お主が姉を止めてみろ！","ENG":"You, Little Sister! You talk some sense into her!","TWN":"堂主的妹妹！你也說幾句話勸勸你姊姊吧！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그자들은 이미 저희 가문의 정보를 너무 많이 알고 있습니다.","JPN":"あの者たちはすでに我が家門の情報をあまりにも多く知っています。","ENG":"They already know too much about our family.","TWN":"那些人對我們家族的底細瞭若指掌，"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"저희가 나서 그들을 타진하지 않으면, 부정한 연구는 멈추지 않겠지요.","JPN":"私たちが出ていって彼らを一網打尽にしないかぎり、不正な研究は止まらないでしょう。","ENG":"If we do not strike first, their corrupted research will only continue.","TWN":"我們要是不出手試一下，那些不人道的研究是不會停止的。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"너까지…… 그런 무모한 짓에 동참할 셈이냐?","JPN":"お主まで……あんな無茶な作戦に加わるつもりなのか？","ENG":"Even you... You agree to this recklessness?!","TWN":"怎麼連你也……你也同意這個衝動的決定嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"지금 상태로 나서는 건 위험해요, 치후유.","JPN":"今の状態のまま出るのは危険です、千冬。","ENG":"Chifuyu, it is too dangerous for you in your current condition.","TWN":"千冬，以你現在的身體狀態會有危險。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"당주님의 호위는 접니다. 부디 허락해주십시오.","JPN":"私は当主の護衛です。どうかお許しを。","ENG":"Lady Nanahara, I am still your bodyguard. Please give me your permission.","TWN":"我是堂主的護衛，請允許我同行！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"알겠습니다.","JPN":"わかりました。","ENG":"Very well.","TWN":"好吧。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그자들이 노리는 게 저희 두 사람이라면, 함께 움직이는 편이 오히려 안전하겠죠.","JPN":"彼らの狙いが私たち二人であるなら、一緒に動いた方がむしろ安全でしょう。","ENG":"If they are after us two, it will be safer to move together.","TWN":"若他們的目標是我們二個，那一起行動反倒安全。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"끄응…… 이것들이.","JPN":"ぐぬぬ……こやつら。","ENG":"Ugh... You two...","TWN":"欸欸……你們這些人！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"저 또한 기다리기만 하는 것은 해답이 아니라고 생각합니다.","JPN":"私もまた待っているだけでは解決できないと思っております。","ENG":"I also think just waiting is not a solution.","TWN":"我也不認為等待是解答。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"하야미의 후손…… 너까지?","JPN":"速水の子孫……お主まで？","ENG":"Even you...? Descendant of Hayami?","TWN":"速水的後裔……連你也？？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"나오님은 일전에 상대하셨던 여인을 기억하시는지요?","JPN":"ナオ様はこの前相手した女を覚えておられますか？","ENG":"Do you remember the girl you fought against the other day?","TWN":"奈緒大人，您還記得之前交手過的那個女人嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"음침한 가면 계집? 그 녀석이 왜?","JPN":"陰険な仮面娘？　あやつがどうした？","ENG":"You mean that bleak looking masked girl? What about her?","TWN":"你說那個面具心機女？怎麼突然提到她？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"그 자가 사라진 선대당주님과 같은 눈을 가지고 있었습니다.","JPN":"あの者は消えた先代当主と同じ目を持っていました。","ENG":"She had the same eyes as the previous Lady Nanahara who went missing.","TWN":"她的眼睛和消失的先祖堂主一樣。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"……뭐?","JPN":"……何じゃと？","ENG":"...What?","TWN":"……什麼？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그렇다면 그 실험이라는 것이 설마……?","JPN":"だとすると、その実験というのはまさか……？","ENG":"Then could that experiment be...?","TWN":"那那個實驗該不會……？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"제프티 바이오테크. 얼마 전 그 위장기업의 버려진 비밀시설에서 무녀를 복제하려던 실험 일지가 발견되었습니다.","JPN":"ジェフティ・バイオテック。最近その偽装企業の捨てられた秘密施設で、巫女を複製しようとした実験の日誌が発見されました。","ENG":"Jehuty Biotech. Lately, research documents about cloning a priestess in an abandoned secret facility of the shell company have been discovered.","TWN":"傑夫堤生物科技，不久之前在那間偽裝企業的一個廢棄密室裡發現一本實驗記錄，裡面是關於複製巫女的內容。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"다른 제공처가 있는지는 확인하지 못했지만, 시도한 선례가 있다는 것은 확실하지요.","JPN":"他にも提供先があるかどうかは確認しておりませんが、試みた前例があるということは確かです。","ENG":"We have not confirmed whether there are any other providers, but what we do know is that there is precedent.","TWN":"雖然無法確認是否有其他供應來源，但可以確定的是，有人正嘗試這麼做。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"하바키는 또다시 그런 일을 벌이기 위해 당주님을 노리고 있는 겁니다.","JPN":"覇吐は再び同じことをするために当主様を狙っているのです。","ENG":"Habaki is trying to kidnap Lady Nanahara so he can restart the experiments.","TWN":"幅木應該也是想要重啟那個實驗，才會對堂主下手。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"끄응……","JPN":"ぐぬぬ……","ENG":"Urgh...","TWN":"嗯嗯……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"그러고보니 그 녀석…… 내 움직임을 다 알고 있는 듯이 반응했지.","JPN":"そういえばあやつ……わしの動きを全部知ってるかのように反応していたのう。","ENG":"Come to think of it... She reacted as if she knew what my next move was going to be.","TWN":"這麼說來……那傢伙的反應彷彿是知道我所有的行動似的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"자기 통각을 자극하는 그 행동도…… 옛 시절, 무녀들이 바람의 목소리를 경청하기 위해 종종 치르던 의식이다.","JPN":"自己痛覚を刺激するあの行動も……昔、巫女たちが風の音に耳を傾けるためによくしていた儀式だ。","ENG":"Even her behavior of stimulating her pain receptors... That was a ritual that priestesses used to perform in order to hear the voice of wind.","TWN":"還有那個刺激自己痛覺的舉動也是……很像以前巫女常常因為要傾聽風聲而舉辦的儀式。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"……하지만 그건 어디까지나 가능성이다.","JPN":"……だがそれは可能性に過ぎん。","ENG":"...But this is all hypothetical.","TWN":"……不過這也只是猜測而已。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"설령 실험이 성공했다고 해도, 어디까지나 모방일 뿐. 진짜 무녀라고는 할 수 없어.","JPN":"たとえ実験が成功していたとしても、あくまでも模倣。本物の巫女とはいえない。","ENG":"Even though they succeed in cloning, it will only be an imitation. It cannot be called a real priestess.","TWN":"就算實驗成功也終究是仿冒，不能算是真正的巫女。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"하지만 놈들의 의도가 어찌됐든……","JPN":"だがやつらの意図が何であれ……","ENG":"Whatever their intentions are with it...","TWN":"重點是，無論那些傢伙的意圖是什麼……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"……신의 힘을 함부로 다룬 대가는 응당 치르게 해야겠지.","JPN":"……神の力をむやみに扱った代償はきっちり払わせるべきじゃ。","ENG":"...I will make them pay for meddling with godly powers.","TWN":"……我都要讓他們付出褻瀆神力應有的代價。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"온 도시에 수색령이 떨어졌는데, 고작 이런 폐공장에 그 많은 병력을 숨기고도 들키지 않다니.","JPN":"都市全体に捜索命令が出されているのに、あの数の兵力をこんな廃工場なぞに隠して見つからぬとは。","ENG":"The entire city is being searched, but our troops are yet to be discovered hiding in this abandoned factory.","TWN":"現在已經對整座城市下搜索令，竟然可以將這麼多兵力藏在這裡，還不被發現，"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"예견의 힘이 아니라면 엄두도 못 낼 계획이군.","JPN":"予言の力がなかったら考えもつかない計画だな。","ENG":"This would have never been possible without the power of foresight.","TWN":"要不是有預知的能力，怎麼可能想得到這個計畫。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"레노어에겐 어렵지 않은 일이오. 미래의 위험을 감지하고 배제하는 것이지.","JPN":"レノアにとっては何ということもない。未来の危険を感知し排除するくらいは。","ENG":"To detect future dangers and exclude them, it is not a difficult task for Lenore.","TWN":"這對蕾諾雅而言並非難事，就是感應到未來的危險後進行排除而已。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"관측에 의하면 곧 무녀가 자신의 위치를 알릴 거요. 우리는 그곳으로 가서 그자를 사로잡으면 되오.","JPN":"観測によるとすぐ巫女が自分の位置を知らせてくる。我らはそちらへ向かってあの者をとらえればいい。","ENG":"According to predictions, the girl will announce her location soon. We will be waiting at the location to capture her.","TWN":"藉由觀測很快就可以知道巫女的位置，我們只要去那裡抓人就好。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"일이 쉽게 풀리는군.","JPN":"仕事がはかどるな。","ENG":"Things are going according to plan.","TWN":"似乎都順利呢。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"그나저나 자네 딸은 어디로 간 거지? 아까부터 보이지 않는데.","JPN":"それよりお前の娘はどこにいる？　さっきから姿が見えないが。","ENG":"By the way, where is your daughter? I haven't seen her yet today.","TWN":"不過你女兒人呢？怎麼從剛才就沒看到她？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"모든 것은 계획대로 되고 있으니 걱정마시오.","JPN":"すべては計画どおりだ、心配するな。","ENG":"Everything is going according to plan. Do not worry.","TWN":"目前都在計畫中，請放心。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"……뭔가 이상하군.","JPN":"……妙だな。","ENG":"...That's strange.","TWN":"……總覺得哪裡不對勁。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"이상하다?","JPN":"妙とは？","ENG":"Strange?","TWN":"不對勁？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"나나하라 치나츠가 미래를 알고 있었다면, 제 동생이 혼자 움직이게 내버려뒀을 리 없어.","JPN":"七原千夏が未来を知っているなら、妹を一人で行動させるはずがない。","ENG":"If Nanahara Chinatsu knows the future, she would not let her sister go out alone.","TWN":"七原千夏能預知未來的話，怎麼會放她妹妹獨自行動？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"바람의 목소리를 듣는 나나하라의 무녀가 이렇게 쉽게 당할 리 없을 텐데.","JPN":"風の声を聞く七原の巫女がそう簡単にやられるはずがないんだが。","ENG":"The priestess of Nanahara can hear the voice of wind. Capturing her will not be as easy.","TWN":"聽得到風聲的七原巫女怎麼可能這麼容易就中招？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"설마…… 우리가 데려가기도 전에 능력을 잃어버리기라도 한 건 아니겠지?","JPN":"まさか……すでに能力を失っているのではないだろうな？","ENG":"Could it be...? What if she has lost her ability before we kidnap her?","TWN":"還是……在我們出手之前她便已經失去能力？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"걱정마시오.","JPN":"心配するな。","ENG":"No need to worry.","TWN":"放心，"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"설령 능력을 잃었다 해도, 유전의 형질은 변하지 않소. 충분한 연구가치가 있을 거요.","JPN":"たとえ能力を失ったとしても、遺伝の形質は変わらない。十分研究する価値があるだろう。","ENG":"Even if she has lost her ability, her DNA does not change. It is still worth studying into.","TWN":"假設她確實是失去能力，但遺傳特徵是不會變的，她仍舊有研究的價值。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"태스크포스 공용채널을 통해 전파합니다.","JPN":"タスクフォースの共用チャンネルにてお知らせいたします。","ENG":"Attention all TASKFORCEs.","TWN":"這裡是特遣勢力共用頻道，"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저희는 나나하라 가문연합. 그리고 저는 나나하라 가문 당주, 나나하라 치나츠입니다.","JPN":"私たちは七原家連合。そして私は七原家の当主、七原千夏です。","ENG":"We are the Nanahara Family Alliance. And I am the head, Nanahara Chinatsu.","TWN":"我們是七原家族聯盟，而我是七原家族的堂主，七原千夏。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"도시관리국의 허가를 받아 침식사태 방어전선에 정식으로 합류하게 되었어요.","JPN":"都市管理局の許可を受け、侵食事態の防御戦線に正式に合流することになりました。","ENG":"We have officially joined the Corruption disaster defense line after receiving permission from the City Management.","TWN":"我們獲得城市管理局的允許，將正式一起投入侵蝕事件防禦戰線。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그러니, 지금부터 저희가 담당하게 된 지역좌표를 공유 드리겠습니다.","JPN":"それでは今から私たちが担当することになった地域座標を共有します。","ENG":"And thus, we will be sharing the coordinates of the areas we are assigned.","TWN":"現在通知各位我們負責的區域座標。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"저쪽도 준비를 모두 마친 듯하니, 슬슬 움직이지.","JPN":"あちらも準備が終わったようだ。そろそろ行こう。","ENG":"They seem to have made all preparations. It is time to move.","TWN":"那邊似乎也已經準備妥當，開始行動吧。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};